%[text] # Exploring NASA Aircraft Flight Data
%[text] This plain-text Live Script loads one NASA DASHlink flight, converts the sensor structs into a timetable, and visualizes a small set of flight parameters from climb through descent.
%%
%[text] ## Load One Flight
%[text] The demo is self-contained: it loads a sample MAT-file from the local `data` folder and converts the nested sensor records into a synchronized timetable.
demoRoot = currentProject().RootFolder;
flightFile = fullfile(demoRoot,"data","652200101092009.mat");
signals = ["ALT","GS","MACH","AOA1","N1.1","N1.2","TAT"];
nt = returnNested(flightFile);
wt = nested2wide(nt,signals);
flightSummary = table(nt.flightid(1),nt.tailnumber(1),nt.starttime(1),height(nt),sum(cellfun(@numel,nt.data)),VariableNames=["FlightID","TailNumber","StartTime","SensorCount","DataPointCount"]);
disp(flightSummary) %[output:28d55605]
%%
%[text] ## Pressure Altitude
%[text] Altitude makes the main flight phases easy to identify: climb, cruise, and descent.
plot(wt.timestamp,wt.ALT) %[output:2d3cffe6]
title("Pressure Altitude") %[output:2d3cffe6]
xlabel("Time") %[output:2d3cffe6]
ylabel("Altitude (ft)") %[output:2d3cffe6]
grid on %[output:2d3cffe6]
%%
%[text] ## Ground Speed
%[text] Ground speed typically rises during takeoff, stabilizes in cruise, and falls during approach.
plot(wt.timestamp,wt.GS) %[output:081f331c]
title("Ground Speed") %[output:081f331c]
xlabel("Time") %[output:081f331c]
ylabel("Speed (knots)") %[output:081f331c]
grid on %[output:081f331c]
%%
%[text] ## Mach Number
%[text] Mach number is the ratio of airspeed to local speed of sound and is a useful cruise-speed indicator.
plot(wt.timestamp,wt.MACH) %[output:92d58c18]
title("Mach Number") %[output:92d58c18]
xlabel("Time") %[output:92d58c18]
ylabel("Mach") %[output:92d58c18]
grid on %[output:92d58c18]
%%
%[text] ## Angle of Attack
%[text] Angle of attack often increases in climb and varies with aircraft configuration and control inputs.
plot(wt.timestamp,wt.AOA1) %[output:647accac]
title("Angle of Attack") %[output:647accac]
xlabel("Time") %[output:647accac]
ylabel("Angle (deg)") %[output:647accac]
grid on %[output:647accac]
%%
%[text] ## Fan Speed
%[text] The two engine fan-speed traces should remain broadly aligned through the flight.
plot(wt.timestamp,wt.("N1.1"),wt.timestamp,wt.("N1.2")) %[output:7cc245aa]
title("Fan Speed (N1)") %[output:7cc245aa]
xlabel("Time") %[output:7cc245aa]
ylabel("%RPM") %[output:7cc245aa]
legend("Engine 1","Engine 2","Location","best") %[output:7cc245aa]
grid on %[output:7cc245aa]
%%
%[text] ## Total Air Temperature
%[text] Temperature is sampled more slowly than the other signals, so NaN values introduced by synchronization are removed before plotting.
valid = ~isnan(wt.TAT);
plot(wt.timestamp(valid),wt.TAT(valid)) %[output:1ec9c3d9]
title("Total Air Temperature") %[output:1ec9c3d9]
xlabel("Time") %[output:1ec9c3d9]
ylabel("Temperature (C)") %[output:1ec9c3d9]
grid on %[output:1ec9c3d9]
%%
%[text] ## Signal Summary
%[text] These seven signals give a compact view of aircraft state, propulsion, and atmosphere.
%[text:table]
%[text] | Signal | Meaning |
%[text] | --- | --- |
%[text] | ALT | Pressure altitude |
%[text] | GS | Ground speed |
%[text] | MACH | Mach number |
%[text] | AOA1 | Angle of attack |
%[text] | N1.1 | Engine 1 fan speed |
%[text] | N1.2 | Engine 2 fan speed |
%[text] | TAT | Total air temperature |
%[text:table]
function nestedTable = returnNested(filename)
arguments
    filename (1,1) string {mustBeNonempty}
end
m = load(filename);
sensorNames = fieldnames(m);
[~,flightID,~] = fileparts(filename);
flightID = extract(flightID,lineBoundary + digitsPattern);
startTime = datetime(extractAfter(flightID,3),InputFormat="yyyyMMddHHmm",Format="yyyy-MM-dd HH:mm:ss.SSS");
tailNumber = uint16(str2double(extractBetween(flightID,1,3)));
flightID = uint64(str2double(flightID));
nestedData = cell(numel(sensorNames),1);
for ii = 1:numel(sensorNames)
    nestedData{ii} = struct2table(m.(sensorNames{ii}),AsArray=true);
end
nestedTable = vertcat(nestedData{:});
nestedTable = renamevars(nestedTable,["Alpha","data","Rate","Units","Description"],["sensorname","data","samplerate","units","description"]);
nestedTable = convertvars(nestedTable,vartype("cellstr"),"string");
nestedTable = convertvars(nestedTable,"units","categorical");
nestedTable = convertvars(nestedTable,"samplerate","single");
nestedTable.data = cellfun(@double,nestedTable.data,UniformOutput=false);
nestedTable.starttime = repelem(startTime,height(nestedTable),1);
nestedTable.tailnumber = repelem(tailNumber,height(nestedTable),1);
nestedTable.flightid = repelem(flightID,height(nestedTable),1);
nestedTable = nestedTable(:,["starttime","tailnumber","flightid","samplerate","sensorname","description","units","data"]);
nestedTable = sortrows(nestedTable,"sensorname");
end
function wideTable = nested2wide(nestedTable,vars)
arguments
    nestedTable table
    vars (:,1) string = ""
end
if vars == ""
    vars = string(unique(nestedTable.sensorname));
end
ts = nestedTable(ismember(string(nestedTable.sensorname),vars),:);
ts.timestamp = ts.starttime;
ts = table2timetable(ts,RowTimes="timestamp");
wideData = cell(1,height(ts));
for ii = 1:numel(wideData)
    wd = ts(ii,:);
    wideData{ii} = repmat(wd(1,["starttime","samplerate","sensorname"]),numel(wd.data{:}),1);
    wideData{ii}.data = wd.data{:};
    wideData{ii} = renamevars(wideData{ii},"data",string(wideData{ii}.sensorname(1)));
    wideData{ii}.timestamp = wideData{ii}.starttime + (0:height(wideData{ii}) - 1)' * seconds(1 / wideData{ii}.samplerate(1));
    wideData{ii} = wideData{ii}(:,string(wideData{ii}.sensorname(1)));
end
wideTable = synchronize(wideData{:},"regular",SampleRate=max(ts.samplerate));
wideTable.timestamp.Format = "yyyy-MM-dd HH:mm:ss.SSS";
end

